using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class InventoryTraining : TrainingContentBase
{
    public InventoryTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Overview",
            Slug = "inventory-overview",
            Summary = "What the Inventory module does: stock tracking, bin locations, movements, receiving from POs, reservations, cycle counts, and replenishment.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/inventory"]""",
            Tags = """["inventory","stock","warehouse","bins"]""",
            ContentJson = """{"body":"## Inventory Overview\n\nThe Inventory module tracks every piece of material and finished goods in your facility — where it is, how much you have, and how it got there. It is the central hub for stock visibility, receiving, transfers, adjustments, and replenishment planning.\n\n### Core Concepts\n\n**Storage Locations** form a hierarchy: Area → Rack → Shelf → Bin. An Area might be 'Warehouse A', a Rack is a physical rack within that area, a Shelf is a level on the rack, and a Bin is a specific slot. Every piece of stock lives in a Bin — the lowest level of the hierarchy. Each location can have a barcode for quick scanning.\n\n**Bin Content** represents what is physically stored in a bin. Each bin content record tracks the entity type (part, production run, assembly, or tooling), quantity, lot number, status (Stored, Reserved, Ready to Ship, or QC Hold), and who placed it there. A single bin can hold multiple items.\n\n**Bin Movements** record every stock movement with full traceability. Each movement captures the item, quantity, source location, destination location, the person who moved it, and the reason (Receive, Pick, Restock, QC Release, Ship, Move, Adjustment, Return, Transfer, or Cycle Count).\n\n### How Inventory Connects to Other Features\n\n**Purchase Orders:** When materials arrive from a vendor, the Receiving tab lets you receive against open PO lines. Select the PO line, enter the quantity received, assign a storage location and optional lot number. This creates a bin content record and a movement record with reason 'Receive'.\n\n**Parts Catalog:** The Stock tab shows inventory summarized by part — total on hand, reserved quantity, and available quantity. Expanding a row reveals the bin-level breakdown showing exactly where each part is stored.\n\n**Jobs and Production:** Stock can be reserved for specific jobs. Reservations reduce the available quantity without moving the physical stock. When production picks the material, the reservation is released and a movement with reason 'Pick' is recorded.\n\n**Quality Control:** Received goods can be placed on QC Hold status, preventing them from being picked or shipped until quality inspection is complete. QC Release changes the status back to Stored and records a movement.\n\n**Shipping:** When orders ship, inventory is decremented with a 'Ship' movement reason. Stock marked as 'Ready to Ship' is staged for outbound shipments.\n\n### Tabs at a Glance\n\n- **Stock** — Part-level inventory summary with expandable bin details. Search by part number. Low stock alerts highlight parts below minimum thresholds.\n- **Locations** — Hierarchical tree view of all storage locations. Create, expand, and browse the Area → Rack → Shelf → Bin structure. Select a bin to see its contents.\n- **Movements** — Chronological log of every stock movement. Shows item, quantity, from/to locations, reason, who moved it, and when.\n- **Receiving** — History of goods received against purchase orders. Receive new stock by selecting an open PO line.\n- **Stock Ops** — Transfer stock between bins or adjust quantities with a reason. Two dialogs: Transfer (move stock from one bin to another) and Adjust (correct a quantity with a mandatory reason).\n- **Cycle Counts** — Create and review cycle counts for specific locations. Each count captures expected vs. actual quantities and calculates variance. Counts can be Pending, Approved, or Rejected.\n- **Reservations** — View and manage stock reservations tied to jobs or sales orders. Create new reservations or release existing ones.\n- **Replenishment** — Burn rate analysis and reorder suggestions. Shows 30/60/90-day consumption rates, days of stock remaining, projected stockout dates, and auto-generated reorder suggestions that can be approved into purchase orders.\n- **UOM** — Unit of measure management and conversions.\n\n### Barcode Scanning\n\nThe Inventory module is scanner-aware. When a barcode is scanned on this page, it automatically populates the search field and switches to the Stock tab. Storage locations can also have barcodes assigned for quick identification during receiving and picking.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory — Guided Tour",
            Slug = "inventory-walkthrough",
            Summary = "A guided tour of the inventory tabs: stock table, receiving, locations tree, movements log, stock operations, cycle counts, reservations, and replenishment.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/inventory"]""",
            Tags = """["inventory","walkthrough"]""",
            ContentJson = """{"appRoute":"/inventory/stock","startButtonLabel":"Tour Inventory","steps":[{"element":".tab-bar","popover":{"title":"Inventory Tabs","description":"The Inventory module is organized into tabs: Stock, Locations, Movements, Receiving, Stock Ops, Cycle Counts, Reservations, Replenishment, and UOM. Click any tab to switch views — the URL updates so you can bookmark or share a direct link to any tab.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Stock Table","description":"The Stock tab shows inventory grouped by part. Each row displays the part number, description, material, on-hand quantity, reserved quantity, and available quantity. Rows turn red when available stock is zero, and yellow when stock is critically low (below 20% of on-hand). Click column headers to sort.","side":"top"}},{"element":"app-input","popover":{"title":"Search Parts","description":"Search by part number, description, or material. Results update when you press Enter or click the search button. Barcode scans automatically populate this field.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(2)","popover":{"title":"Locations Tab","description":"Switch to the Locations tab to see and manage your storage location hierarchy. Locations are organized as Area → Rack → Shelf → Bin. You can create new locations at any level of the hierarchy.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(3)","popover":{"title":"Movements Tab","description":"The Movements tab shows a chronological log of every stock movement. Each entry records what moved, how much, from where, to where, who did it, the reason (Receive, Pick, Ship, Transfer, etc.), and when it happened. This is your complete audit trail.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(4)","popover":{"title":"Receiving Tab","description":"The Receiving tab shows a history of all goods received against purchase orders. Click 'Receive Goods' to record an incoming shipment — select the PO line, enter quantity, assign a storage location, and optionally record a lot number.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(5)","popover":{"title":"Stock Operations Tab","description":"Stock Ops provides two key operations: Transfer (move stock from one bin to another) and Adjust (correct a quantity with a mandatory reason). Both operations create movement records for full traceability.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(6)","popover":{"title":"Cycle Counts Tab","description":"Create cycle counts for specific locations to verify physical stock matches system records. Each count shows expected vs. actual quantities, calculates variance, and can be approved or rejected. Approved counts automatically generate adjustment movements.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(7)","popover":{"title":"Reservations Tab","description":"View all active stock reservations. Reservations hold stock for specific jobs or sales orders without physically moving it. The reserved quantity reduces available stock. Release a reservation when the stock is picked or no longer needed.","side":"bottom"}},{"element":".tab-bar .tab:nth-child(9)","popover":{"title":"Replenishment Tab","description":"Replenishment shows burn rate analysis (30/60/90-day consumption), days of stock remaining, projected stockout dates, and auto-generated reorder suggestions. Approve suggestions to create purchase orders, or dismiss them with a reason.","side":"bottom"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Field Reference",
            Slug = "inventory-field-reference",
            Summary = "Complete reference for every field, column, status, movement reason, location type, button, and validation rule across all Inventory tabs.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/inventory"]""",
            Tags = """["inventory","reference"]""",
            ContentJson = """{"title":"Inventory Field Reference","groups":[{"heading":"Stock Tab — Table Columns","items":[{"label":"Part #","value":"Sortable. The part number from the Parts Catalog. Width: 120px."},{"label":"Description","value":"Sortable. The part description text."},{"label":"Material","value":"Sortable. The material type of the part (e.g., 'Aluminum 6061', 'Steel 1018'). Width: 140px."},{"label":"On Hand","value":"Sortable, right-aligned. Total quantity of this part across all bins. Width: 90px."},{"label":"Reserved","value":"Sortable, right-aligned. Quantity reserved for jobs or sales orders. Width: 90px."},{"label":"Available","value":"Sortable, right-aligned. On Hand minus Reserved. This is the quantity that can be picked or shipped. Width: 90px."}]},{"heading":"Stock Tab — Expanded Bin Detail","items":[{"label":"Location Path","value":"Full hierarchical path to the bin (e.g., 'Warehouse A > Rack 1 > Shelf 3 > Bin 5')."},{"label":"Quantity","value":"Amount of the part in this specific bin."},{"label":"Reserved Quantity","value":"Amount reserved from this bin for jobs/orders."},{"label":"Available Quantity","value":"Bin quantity minus reserved. What can actually be picked."},{"label":"Status","value":"Bin content status: Stored (default), Reserved (held for a job), Ready to Ship (staged for outbound), QC Hold (awaiting inspection)."},{"label":"Lot Number","value":"Optional lot/batch number for traceability. Shown if assigned."},{"label":"Lot Expiration Date","value":"Expiration date for lot-tracked items. Shown if applicable."},{"label":"Supplier Lot Number","value":"The vendor's lot number, distinct from your internal lot number."}]},{"heading":"Stock Tab — Row Highlighting","items":[{"label":"Red row (stock-level--empty)","value":"Available quantity is zero or negative. This part has no pickable stock."},{"label":"Yellow row (stock-level--low)","value":"Available quantity is less than 20% of on-hand. Stock is critically low."},{"label":"Normal row","value":"Adequate stock levels."}]},{"heading":"Low Stock Alerts","items":[{"label":"Part Number","value":"The part that is low on stock."},{"label":"Description","value":"Part description for identification."},{"label":"Current Stock","value":"Current on-hand quantity."},{"label":"Min Stock Threshold","value":"The configured minimum stock level. Alert fires when current stock falls below this."},{"label":"Reorder Point","value":"The configured reorder point. When stock drops to this level, a reorder should be triggered."}]},{"heading":"Location Types","items":[{"label":"Area","value":"Top-level zone (e.g., 'Warehouse A', 'Receiving Dock', 'Shipping Area'). Icon: warehouse."},{"label":"Rack","value":"A physical rack or shelving unit within an area. Icon: view_column."},{"label":"Shelf","value":"A level/shelf on a rack. Icon: shelves."},{"label":"Bin","value":"The lowest level — a specific slot or container. This is where stock is actually stored. Icon: inventory_2."}]},{"heading":"Location Form Fields (Create Location Dialog)","items":[{"label":"Name (required)","value":"Text input. Identifies the location (e.g., 'Rack A1', 'Shelf 3', 'Bin 5'). Must not be empty."},{"label":"Type (required)","value":"Dropdown: Area, Rack, Shelf, Bin. Determines the level in the hierarchy. Default: Area (no parent) or Rack (with parent)."},{"label":"Parent","value":"Not a field in the dialog — the parent is set by where you open it. The page-header 'Add Location' button creates a top-level location (no parent), while the 'Add child' button on a selected location pre-sets that location as the parent."},{"label":"Barcode","value":"Text input, optional. Only shown when Type is Bin. A barcode value assigned to the bin for scanner identification."},{"label":"Description","value":"Text input, optional. Free-form description or notes about the location."}]},{"heading":"Bin Content Statuses","items":[{"label":"Stored","value":"Default status. Stock is available for picking, transfer, or reservation."},{"label":"Reserved","value":"Stock is held for a specific job or sales order. Cannot be picked for other purposes until released."},{"label":"Ready to Ship","value":"Stock has been staged for an outbound shipment. Waiting for the shipment to be dispatched."},{"label":"QC Hold","value":"Stock is awaiting quality inspection. Cannot be picked or shipped until QC releases it."}]},{"heading":"Movement Reasons","items":[{"label":"Receive","value":"Stock received from a purchase order. Recorded automatically when goods are received via the Receiving tab."},{"label":"Pick","value":"Stock picked for production or fulfillment. Removes stock from a bin for a job or order."},{"label":"Restock","value":"Stock returned to a bin after being picked but not used."},{"label":"QC Release","value":"Stock released from QC Hold status after passing inspection."},{"label":"Ship","value":"Stock shipped to a customer. Recorded when a shipment is dispatched."},{"label":"Move","value":"General stock relocation between bins without a specific business reason."},{"label":"Adjustment","value":"Manual quantity correction. Always requires a reason note (e.g., 'damaged', 'miscounted')."},{"label":"Return","value":"Stock returned from a customer or returned to a vendor."},{"label":"Transfer","value":"Formal transfer between bins, typically between different areas or facilities."},{"label":"Cycle Count","value":"Quantity adjustment resulting from a cycle count variance. System-generated when a count is approved."}]},{"heading":"Movements Tab — Table Columns","items":[{"label":"Item","value":"Sortable. The name/number of the item that was moved."},{"label":"Qty","value":"Sortable, right-aligned. Quantity moved. Width: 70px."},{"label":"From","value":"Sortable. Source location path. Blank for incoming movements (e.g., Receive)."},{"label":"To","value":"Sortable. Destination location path. Blank for outgoing movements (e.g., Ship)."},{"label":"Reason","value":"Sortable. Movement reason displayed as a friendly label (e.g., 'Received', 'Picked', 'Transferred'). Width: 120px."},{"label":"By","value":"Sortable. Name of the person who performed the movement."},{"label":"When","value":"Sortable, date type. Timestamp of the movement. Width: 120px."}]},{"heading":"Receiving Tab — Table Columns","items":[{"label":"PO #","value":"Sortable. Purchase order number. Width: 110px."},{"label":"Part #","value":"Sortable. Part number received. Width: 120px."},{"label":"Qty","value":"Sortable, right-aligned. Quantity received. Width: 70px."},{"label":"Received By","value":"Sortable. Name of the person who received the goods."},{"label":"Location","value":"Sortable. Storage location where goods were placed."},{"label":"Lot #","value":"Sortable. Lot or batch number assigned during receiving. Width: 100px."},{"label":"Date","value":"Sortable, date type. Date/time of receiving. Width: 120px."}]},{"heading":"Receive Goods Dialog Fields","items":[{"label":"PO Line (required)","value":"Dropdown showing open PO lines with remaining quantity. Format: 'PO-1001 — Part ABC (50 remaining)'. Only PO lines from Submitted, Acknowledged, or Partially Received purchase orders appear."},{"label":"Quantity Received (required)","value":"Number input. Must be at least 1. The quantity of items received in this shipment."},{"label":"Location","value":"Dropdown of bin locations. Optional. Where the received goods will be stored."},{"label":"Lot Number","value":"Text input, optional. Assign a lot/batch number for traceability."},{"label":"Notes","value":"Text input, optional. Any notes about the receipt (condition, discrepancies, etc.)."}]},{"heading":"Transfer Dialog Fields","items":[{"label":"Source Bin Content (required)","value":"Identifies the specific bin content record being transferred. Pre-populated when opened from a bin detail row."},{"label":"Destination Location (required)","value":"Dropdown of bin locations. Where the stock is being moved to."},{"label":"Quantity (required)","value":"Number input. Must be at least 1. Amount to transfer."},{"label":"Notes","value":"Text input, optional. Reason or notes for the transfer."}]},{"heading":"Adjust Stock Dialog Fields","items":[{"label":"Bin Content (required)","value":"Identifies the specific bin content record being adjusted. Pre-populated when opened from a bin detail row."},{"label":"New Quantity (required)","value":"Number input. Must be 0 or greater. The corrected quantity — replaces the current quantity."},{"label":"Reason (required)","value":"Text input. Mandatory explanation for the adjustment (e.g., 'damaged goods', 'recount corrected', 'scrap'). Cannot be blank."},{"label":"Notes","value":"Text input, optional. Additional details about the adjustment."}]},{"heading":"Cycle Counts Tab — Table Columns","items":[{"label":"Location","value":"Sortable. The storage location that was counted."},{"label":"Counted By","value":"Sortable. Name of the person who performed the count."},{"label":"Date","value":"Sortable, date type. When the count was performed. Width: 120px."},{"label":"Status","value":"Sortable, filterable (enum). Pending (awaiting review), Approved (adjustments applied), or Rejected (discarded). Width: 110px."},{"label":"Items","value":"Sortable, right-aligned. Number of line items in the count. Width: 70px."},{"label":"Variance","value":"Sortable, right-aligned. Total absolute variance across all lines. Width: 90px."}]},{"heading":"Cycle Count Line Fields","items":[{"label":"Entity Name","value":"The part or item being counted."},{"label":"Expected Quantity","value":"System-recorded quantity in the bin before the count."},{"label":"Actual Quantity","value":"Physically counted quantity."},{"label":"Variance","value":"Actual minus Expected. Positive = surplus, negative = shortage."},{"label":"Notes","value":"Optional notes explaining the variance."}]},{"heading":"Create Cycle Count Dialog Fields","items":[{"label":"Location (required)","value":"Dropdown of storage locations. Select the bin or location to count."},{"label":"Notes","value":"Text input, optional. Notes for the count (e.g., 'quarterly audit', 'spot check')."}]},{"heading":"Reservations Tab — Table Columns","items":[{"label":"Part #","value":"Sortable. Part number of the reserved stock. Width: 120px."},{"label":"Description","value":"Sortable. Part description."},{"label":"Bin Location","value":"Sortable. Full location path where the reserved stock sits."},{"label":"Qty","value":"Sortable, right-aligned. Quantity reserved. Width: 80px."},{"label":"Job #","value":"Sortable. Job number the stock is reserved for (if applicable). Width: 100px."},{"label":"Job","value":"Sortable. Job title."},{"label":"Notes","value":"Not sortable. Reservation notes."},{"label":"Reserved","value":"Sortable, date type. When the reservation was created. Width: 120px."},{"label":"Actions","value":"Release button to remove the reservation. Width: 60px."}]},{"heading":"Create Reservation Dialog Fields","items":[{"label":"Part ID (required)","value":"Identifies the part to reserve."},{"label":"Bin Content ID (required)","value":"Identifies the specific bin content to reserve from."},{"label":"Job ID","value":"Optional. The job this reservation is for. Links the reservation to a production job."},{"label":"Quantity (required)","value":"Number input. Must be greater than 0. Amount to reserve."},{"label":"Notes","value":"Text input, optional. Why the stock is being reserved."}]},{"heading":"Replenishment Tab — Burn Rate Columns","items":[{"label":"Part Number / Description","value":"The part being analyzed."},{"label":"Preferred Vendor","value":"The configured preferred vendor for this part."},{"label":"On Hand Stock","value":"Current total on-hand quantity."},{"label":"Available Stock","value":"On hand minus reserved."},{"label":"Incoming PO Quantity","value":"Quantity on open purchase orders not yet received."},{"label":"Earliest PO Arrival","value":"Expected arrival date of the earliest open PO."},{"label":"Burn Rate (30/60/90 Day)","value":"Average daily consumption over the last 30, 60, or 90 days."},{"label":"Days of Stock Remaining","value":"Calculated from available stock divided by burn rate."},{"label":"Projected Stockout Date","value":"Estimated date when stock will reach zero at the current burn rate."},{"label":"Min Stock Threshold","value":"Configured minimum stock level."},{"label":"Reorder Point","value":"Stock level that triggers a reorder."},{"label":"Reorder Quantity","value":"Suggested order quantity."},{"label":"Lead Time Days","value":"Expected supplier lead time."},{"label":"Safety Stock Days","value":"Buffer days of stock to maintain above lead time."},{"label":"Needs Reorder","value":"Boolean flag. True when available stock is at or below the reorder point."}]},{"heading":"Replenishment Tab — Reorder Suggestions","items":[{"label":"Suggestion Status","value":"Pending (awaiting decision), Approved (PO created), Dismissed (rejected with reason), Expired (no longer relevant)."},{"label":"Suggested Quantity","value":"System-calculated reorder quantity based on burn rate, lead time, and safety stock."},{"label":"Resulting PO","value":"If approved, links to the purchase order that was created."},{"label":"Dismiss Reason","value":"Required when dismissing a suggestion. Explains why the reorder was not needed."},{"label":"Bulk Approve","value":"Select multiple suggestions and approve them all at once. Creates purchase orders grouped by vendor."}]},{"heading":"Buttons and Actions","items":[{"label":"Receive Goods (Receiving tab)","value":"Opens the receive dialog. data-testid: receive-goods-btn"},{"label":"Create Location (Locations tab)","value":"Opens the create location dialog. data-testid: add-location-btn"},{"label":"Transfer (Stock Ops tab)","value":"Opens the transfer stock dialog."},{"label":"Adjust (Stock Ops tab)","value":"Opens the adjust stock dialog."},{"label":"Create Cycle Count","value":"Opens the create cycle count dialog."},{"label":"Create Reservation","value":"Opens the create reservation dialog."},{"label":"Release (Reservations tab)","value":"Releases a stock reservation, making the quantity available again."},{"label":"Create PO (Low Stock alert)","value":"Navigates to the Purchase Orders page to create a new PO for the low-stock part."},{"label":"Search / Clear","value":"Search filters the stock table by part number/description/material. Clear resets the search."}]},{"heading":"Barcode Scanner Integration","items":[{"label":"Scan behavior","value":"When a barcode is scanned while on the Inventory page, the scanned value is placed into the search field and the view switches to the Stock tab. Context: 'inventory'."},{"label":"Location barcodes","value":"Each storage location can have an assigned barcode for quick identification during receiving and stock operations."}]},{"heading":"Validation Rules","items":[{"label":"Location Name","value":"Required. Cannot be empty."},{"label":"Location Type","value":"Required. Must be one of: Area, Rack, Shelf, Bin."},{"label":"PO Line (Receiving)","value":"Required. Must select an open PO line with remaining quantity."},{"label":"Quantity Received","value":"Required. Must be at least 1."},{"label":"Transfer Source","value":"Required. Must select a bin content record."},{"label":"Transfer Destination","value":"Required. Must select a destination location."},{"label":"Transfer Quantity","value":"Required. Must be at least 1."},{"label":"Adjust Reason","value":"Required. Cannot be blank — every adjustment must be explained for audit purposes."},{"label":"Adjust New Quantity","value":"Required. Must be 0 or greater."},{"label":"Cycle Count Location","value":"Required. Must select a location to count."},{"label":"Reservation Part / Bin Content","value":"Required. Must identify the part and specific bin content."},{"label":"Reservation Quantity","value":"Required. Must be greater than 0."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Knowledge Check",
            Slug = "inventory-quiz",
            Summary = "Test your knowledge of the Inventory module: stock tracking, locations, movements, receiving, cycle counts, reservations, and replenishment.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/inventory"]""",
            Tags = """["inventory","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"inv1","text":"A shipment of raw materials just arrived from your vendor with a purchase order. How do you record it in QB Engineer?","options":[{"id":"a","text":"Go to Inventory → Receiving tab, click Receive Goods, select the PO line, enter quantity, assign a location, and optionally record a lot number","isCorrect":true},{"id":"b","text":"Go to Parts Catalog and manually increase the on-hand quantity for each part"},{"id":"c","text":"Create a new bin movement with reason 'Receive' in the Movements tab"},{"id":"d","text":"Go to Purchase Orders and mark the PO as 'Received'"}],"explanation":"Receiving is done from the Inventory → Receiving tab. Click Receive Goods, select the open PO line (only lines with remaining quantity appear), enter the quantity received, optionally assign a storage location and lot number. This automatically creates a bin content record, updates the PO line, and logs a movement with reason 'Receive'."},{"id":"inv2","text":"What is the correct hierarchy for storage locations in the Inventory module?","options":[{"id":"a","text":"Warehouse → Zone → Aisle → Position"},{"id":"b","text":"Building → Floor → Room → Cabinet"},{"id":"c","text":"Area → Rack → Shelf → Bin","isCorrect":true},{"id":"d","text":"Section → Row → Column → Slot"}],"explanation":"Storage locations follow the hierarchy Area → Rack → Shelf → Bin. Area is the top level (e.g., 'Warehouse A'), Rack is a shelving unit within an area, Shelf is a level on the rack, and Bin is the lowest level where stock is actually stored."},{"id":"inv3","text":"You notice the on-hand quantity for a part doesn't match what's physically on the shelf. What's the correct way to fix this?","options":[{"id":"a","text":"Edit the bin content record directly in the database"},{"id":"b","text":"Go to Stock Ops tab, click Adjust, select the bin content, enter the correct quantity, and provide a mandatory reason","isCorrect":true},{"id":"c","text":"Delete the bin content and re-create it with the correct quantity"},{"id":"d","text":"Create a Transfer moving stock to the same bin with the corrected amount"}],"explanation":"Stock adjustments are done via the Adjust dialog on the Stock Ops tab. You must provide the new quantity and a mandatory reason (e.g., 'recount corrected', 'damaged goods'). This creates a movement record with reason 'Adjustment' for full audit traceability. The reason field cannot be left blank."},{"id":"inv4","text":"A row in the Stock table is highlighted in red. What does this indicate?","options":[{"id":"a","text":"The part has been discontinued and should not be reordered"},{"id":"b","text":"The available quantity is zero or negative — there is no pickable stock","isCorrect":true},{"id":"c","text":"The part is on QC Hold and cannot be used"},{"id":"d","text":"The part's lot has expired and must be disposed of"}],"explanation":"A red row in the Stock table means the available quantity (on hand minus reserved) is zero or negative. This means there is no stock available to pick or ship. A yellow row indicates low stock (available is less than 20% of on-hand)."},{"id":"inv5","text":"What is the difference between the 'Reserved' bin content status and a 'Reservation' record?","options":[{"id":"a","text":"They are the same thing — both refer to stock held for a job"},{"id":"b","text":"'Reserved' is the bin content status flag, while a Reservation is a separate record linking stock to a specific job or sales order with quantity and notes","isCorrect":true},{"id":"c","text":"'Reserved' applies to entire bins, while Reservations apply to individual items"},{"id":"d","text":"'Reserved' is for customer-owned stock, while Reservations are for internal use"}],"explanation":"'Reserved' is a status on a bin content record indicating the stock is held. A Reservation is a separate record that links a specific quantity from a bin content to a job or sales order, with optional notes. Reservations reduce the 'available' quantity shown in the Stock tab. Releasing a reservation makes the quantity available again."},{"id":"inv6","text":"You need to move 50 units of a part from Warehouse A, Rack 1, Bin 3 to Warehouse B, Rack 2, Bin 1. Which feature do you use?","options":[{"id":"a","text":"Create a new Receive record with the destination bin"},{"id":"b","text":"Go to Stock Ops tab, click Transfer, select the source bin content, choose the destination bin, and enter quantity 50","isCorrect":true},{"id":"c","text":"Delete the stock from the first bin and place new stock in the second bin"},{"id":"d","text":"Use the Movements tab to manually create a movement record"}],"explanation":"Stock transfers are done via the Transfer dialog on the Stock Ops tab. Select the source bin content record, choose the destination location, and enter the quantity. This creates a movement record with reason 'Transfer' and updates both bin contents automatically."},{"id":"inv7","text":"What movement reasons are automatically generated by the system (not manually created)?","options":[{"id":"a","text":"Receive (from PO receiving) and Cycle Count (from approved cycle counts)","isCorrect":true},{"id":"b","text":"All reasons are manually selected by the user"},{"id":"c","text":"Only Ship and Pick are automatic"},{"id":"d","text":"Move and Transfer are the only automatic reasons"}],"explanation":"'Receive' movements are automatically created when goods are received against a PO line via the Receiving tab. 'Cycle Count' movements are auto-generated when a cycle count with variance is approved, creating adjustment records. Other reasons like Transfer, Adjustment, Pick, and Ship are created through their respective operations."},{"id":"inv8","text":"A cycle count shows a variance of -5 for a part in Bin 12. What does this mean?","options":[{"id":"a","text":"Five extra units were found that the system didn't know about"},{"id":"b","text":"The system expected 5 more units than were physically counted — there is a shortage of 5","isCorrect":true},{"id":"c","text":"Five units were moved to a different bin during the count"},{"id":"d","text":"The count was rejected because the variance exceeds the threshold"}],"explanation":"A negative variance means the actual count was lower than the expected (system) quantity. A variance of -5 means 5 fewer units were found than the system recorded. When the cycle count is approved, an adjustment movement is created to correct the system quantity to match the physical count."},{"id":"inv9","text":"Which PO statuses allow receiving goods in the Inventory module?","options":[{"id":"a","text":"Only 'Submitted' purchase orders can be received against"},{"id":"b","text":"Submitted, Acknowledged, and Partially Received","isCorrect":true},{"id":"c","text":"Any PO status except Cancelled and Closed"},{"id":"d","text":"Only 'Acknowledged' — the vendor must confirm before receiving is allowed"}],"explanation":"The Receive Goods dialog only shows PO lines from purchase orders with status Submitted, Acknowledged, or Partially Received. Additionally, only lines with remaining quantity (ordered minus already received) greater than zero are shown."},{"id":"inv10","text":"What does the 'Days of Stock Remaining' metric on the Replenishment tab represent?","options":[{"id":"a","text":"The number of days until the next scheduled delivery arrives"},{"id":"b","text":"Available stock divided by the average daily consumption (burn rate) — how long current stock will last at the current usage rate","isCorrect":true},{"id":"c","text":"The number of business days since the last stock receipt"},{"id":"d","text":"The lead time in days for the preferred vendor to deliver"}],"explanation":"Days of Stock Remaining is calculated by dividing available stock by the burn rate (average daily consumption). For example, if you have 100 units available and consume 10 per day, you have 10 days of stock remaining. This drives the Projected Stockout Date and reorder suggestions."},{"id":"inv11","text":"You scan a barcode while on the Inventory page. What happens?","options":[{"id":"a","text":"A dialog opens asking what action to take with the scanned code"},{"id":"b","text":"The scanned value is placed in the search field and the view switches to the Stock tab","isCorrect":true},{"id":"c","text":"The system looks up the barcode in the location database and navigates to that bin"},{"id":"d","text":"Nothing — barcode scanning only works on the Shop Floor display"}],"explanation":"The Inventory module is scanner-aware with context 'inventory'. When a barcode is scanned, the value is automatically placed into the search field and the view switches to the Stock tab. This lets you quickly look up a part by scanning its label."},{"id":"inv12","text":"What is the 'QC Hold' bin content status used for?","options":[{"id":"a","text":"Stock that has failed quality inspection and must be scrapped"},{"id":"b","text":"Stock awaiting quality inspection — it cannot be picked or shipped until QC releases it","isCorrect":true},{"id":"c","text":"Stock that is reserved for quality control testing samples"},{"id":"d","text":"Stock returned by a customer pending quality review"}],"explanation":"QC Hold prevents stock from being picked or shipped until it passes quality inspection. Once inspection is complete, a 'QC Release' movement changes the status back to Stored, making the stock available. This is commonly used for incoming materials that require inspection before use in production."},{"id":"inv13","text":"How are reorder suggestions created in the Replenishment tab?","options":[{"id":"a","text":"Users manually create suggestions by clicking 'Add Suggestion'"},{"id":"b","text":"The system automatically generates suggestions based on burn rate analysis, reorder points, lead times, and safety stock levels","isCorrect":true},{"id":"c","text":"Suggestions are imported from the vendor's catalog system"},{"id":"d","text":"They are copied from the previous month's purchase orders"}],"explanation":"Reorder suggestions are system-generated based on burn rate analysis (30/60/90-day consumption), configured reorder points, lead times, and safety stock days. When available stock drops to or below the reorder point, a suggestion is created with a calculated order quantity. Suggestions can be approved (creating a PO) or dismissed (with a required reason)."},{"id":"inv14","text":"You want to create a new storage location called 'Bin 7' inside 'Rack B2' in 'Warehouse A'. What do you set in the Create Location dialog?","options":[{"id":"a","text":"Name: 'Bin 7', Type: Bin, Parent: select 'Rack B2' from the dropdown","isCorrect":true},{"id":"b","text":"Name: 'Warehouse A > Rack B2 > Bin 7', Type: Area, no parent"},{"id":"c","text":"Name: 'Bin 7', Type: Shelf, Parent: 'Warehouse A'"},{"id":"d","text":"You must first create 'Bin 7' as an Area, then move it under Rack B2"}],"explanation":"To create a bin inside an existing rack, set the Name to 'Bin 7', select Type as 'Bin' (the lowest level), and set the Parent to 'Rack B2' from the dropdown. The system will nest it in the hierarchy: Warehouse A → Rack B2 → Bin 7. The full path is displayed in stock tables and movement logs."},{"id":"inv15","text":"What happens when you approve a cycle count that has variances?","options":[{"id":"a","text":"The variances are logged but no quantities are changed — you must manually adjust each one"},{"id":"b","text":"Adjustment movements are automatically generated to correct system quantities to match the physical counts","isCorrect":true},{"id":"c","text":"An email is sent to the warehouse manager listing all discrepancies"},{"id":"d","text":"The count is flagged for a second verification before any changes are made"}],"explanation":"Approving a cycle count with variances automatically generates adjustment movements with reason 'Cycle Count' to correct the system quantities. Each line with a non-zero variance gets an adjustment to make the system quantity match the actual counted quantity. This maintains the audit trail while keeping inventory accurate."}]}"""
        });

        // ── Inventory Home (Article) ─────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Home — The Friendly Landing",
            Slug = "inventory-home",
            Summary = "The default Inventory landing built for the shop floor: three tabs (Kiosk, Tasks, Dashboard) over friendly stock verbs — Receive, Use, Count, Find — with a one-click jump to the detailed power view.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 5,
            AppRoutes = """["/inventory/home/kiosk","/inventory/home/tasks","/inventory/home/dashboard"]""",
            Tags = """["inventory","home","kiosk","stock","verbs"]""",
            ContentJson = """{"body":"## Inventory Home\n\nWhen you open Inventory, you land on **Inventory Home** — not the detailed tab grid. Home is a deliberately simple, low-friction surface designed for the people who actually touch stock: receiving clerks, machinists, and anyone who needs to record a stock change in a few taps without learning the full warehouse model.\n\nThe URL is `/inventory/home/kiosk`. Home has three tabs across the top, and the tab name is part of the URL so you can bookmark or share a direct link (`/inventory/home/tasks`, `/inventory/home/dashboard`).\n\n### Two views of inventory, one feature\n\nForge ships **two** inventory surfaces over the same data:\n\n- **Inventory Home** (where you land) — friendly verbs, big buttons, three at-a-glance tabs. Built for daily floor use.\n- **The detailed power view** (Stock / Locations / Movements / Receiving / Stock Ops / Cycle Counts / Reservations / Replenishment / UOM) — the full warehouse model with bins, lots, and audit trails. Reach it from the **Manage Inventory** link in the top-right of Home, or by navigating to `/inventory/stock` directly.\n\nNothing you do on Home is \"different data\" — receiving a part on Home and receiving it on the detailed Receiving tab both write the same bin contents and the same movement records. Home is just a faster door into the same warehouse.\n\n### The friendly stock verbs\n\nHome is organized around four plain-language verbs instead of warehouse jargon:\n\n- **Receive** — stock came IN. Add quantity to a part (e.g., a delivery arrived, or you finished making something). Receive also lets you record a lot number.\n- **Use** — stock went OUT. Subtract quantity from a part (e.g., it was consumed by a job or scrapped).\n- **Count** — set the TRUE on-hand quantity. Use this when you physically counted the shelf and want the system to match reality. Count overwrites the on-hand number rather than adding or subtracting.\n- **Find** — look up a part. On the Kiosk tab this jumps you to the Tasks tab so you can search; it is a navigation shortcut, not a stock change.\n\nReceive, Use, and Count each open a small dialog: pick the part (pre-filled if you started from a row), enter a quantity, optionally pick a location and add a reason/notes. Receive additionally shows a Lot number field. Tap the action button and the change is recorded immediately with a confirmation snackbar.\n\n### The three tabs\n\n**Kiosk (default).** Four big touch-friendly buttons — Receive, Use, Count, Find — arranged two-per-row. This is the tap-and-go view for a wall-mounted tablet or a quick action at a workstation. One action at a time, nothing else competing for attention.\n\n**Tasks.** A working list: a search box, a row of the same verb buttons, a low-stock strip, and a table of parts with on-hand quantities. Each table row has inline Receive and Use buttons so you can act on a specific part without retyping its number. If a part is below its minimum, it shows up as a warning chip in the low-stock strip — tap the chip to Receive against it.\n\n**Dashboard.** At-a-glance numbers: total parts tracked, total units on hand, and a low-stock count (which turns amber when anything is low). Below the numbers is the full low-stock list — part number, description, current-vs-minimum quantity, and a Receive shortcut on each line. When nothing is low, you get a clean \"all stocked\" confirmation.\n\n### Locations are optional here\n\nIf your install runs single-location inventory, the **Location** field is hidden in the verb dialogs and the server quietly puts everything in the default location — you don't have to think about bins. If multi-location is enabled (the `CAP-INV-MULTILOC` capability), the Location dropdown appears so you can say exactly which bin the stock went into or came out of. Either way, the verb itself is the same; only the optional location detail changes.\n\n### When to use Home vs. the detailed view\n\nUse **Home** for the everyday actions: a delivery arrived, a job consumed material, you recounted a shelf, you need to glance at what's low. Use the **detailed view** when you need the warehouse mechanics: moving stock between specific bins, transferring between areas, running and approving cycle counts, managing reservations against jobs, receiving formally against a purchase-order line, or reviewing the full movement audit trail and replenishment analysis.","sections":[]}"""
        });

        // ── Inventory Home — Guided Tour (Walkthrough) ───────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Inventory Home — Guided Tour",
